ExternalServiceRegistration.schema:
{
  "openapi": "3.0.1",
  "info": {
    "title": "Trustmark Business Search",
    "version": "1.0.0",
    "description": "API to retrieve business profiles from Trustmark using licence number."
  },
  "paths": {
    "/business-profiles": {
      "get": {
        "summary": "Get Business Profile by Licence Number",
        "operationId": "getBusinessProfile",
        "parameters": [{
            "name": "licenceNumber",
            "in": "query",
            "required": true,
            "schema": {
              "type": "string"
            },
            "description": "Licence number to search by"
          },
          {
            "name": "pageindex",
            "in": "query",
            "required": false,
            "schema": {
              "type": "string"
            },
            "description": "Page index for paginated results"
          }
        ],
        "responses": {
          "200": {
            "description": "Successful response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "results": {
                      "type": "array",
                      "description": "List of business profiles matching the licence number",
                      "items": {
                        "type": "object",
                        "properties": {
                          "id": {
                            "type": "string",
                            "description": "Unique identifier for the business"
                          },
                          "companyName": {
                            "type": "string",
                            "description": "Name of the company"
                          },
                          "tradingStandardsApproved": {
                            "type": "boolean",
                            "description": "Indicates if approved by trading standards"
                          },
                          "nationalBusiness": {
                            "type": "boolean",
                            "description": "Indicates if operates nationally"
                          },
                          "aboutInformation": {
                            "type": "string",
                            "description": "Additional information"
                          },
                          "address": {
                            "type": "object",
                            "description": "Business address",
                            "properties": {
                              "town": {
                                "type": "string",
                                "description": "Town"
                              },
                              "county": {
                                "type": "string",
                                "description": "County"
                              },
                              "postcode": {
                                "type": "string",
                                "description": "Postal code"
                              }
                            }
                          },
                          "trades": {
                            "type": "array",
                            "description": "List of trades the business is involved in",
                            "items": {
                              "type": "object",
                              "properties": {
                                "tradeCode": {
                                  "type": "integer",
                                  "description": "Code of the trade"
                                },
                                "name": {
                                  "type": "string",
                                  "description": "Trade name"
                                },
                                "description": {
                                  "type": "string",
                                  "description": "Trade description"
                                }
                              }
                            }
                          },
                          "phoneNumbers": {
                            "type": "array",
                            "description": "List of phone numbers",
                            "items": {
                              "type": "string"
                            }
                          },
                          "websites": {
                            "type": "array",
                            "description": "List of websites",
                            "items": {
                              "type": "string"
                            }
                          },
                          "communicationsPlatformLink": {
                            "type": "string",
                            "description": "Trustmark profile link"
                          },
                          "tmln": {
                            "type": "string",
                            "description": "Trustmark licence number"
                          }
                        }
                      }
                    },
                    "totalItemsCount": {
                      "type": "integer",
                      "description": "Total number of items returned"
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
